# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(transactions, balances):
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        if account_id in balances:
            balances[account_id] += amount
        else:
            balances[account_id] = amount
    return balances

# Example usage
transactions = [
    {'account_id': 'A123', 'amount': 100},
    {'account_id': 'B456', 'amount': -50},
    {'account_id': 'A123', 'amount': -20},
]
balances = {'A123': 200, 'B456': 300}

updated_balances = process_transactions(transactions, balances)
print(updated_balances)